// 스케줄(08:00) → 전일 확정, 웹훅 → body.mode 참조
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');
const mode = (body.mode || 'yesterday').toLowerCase();

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

let targetDate, label;
if (mode === 'today') {
  targetDate = kstNow.toISOString().slice(0, 10);
  const h = kstNow.getHours();
  const min = String(kstNow.getMinutes()).padStart(2, '0');
  label = `${kstNow.getMonth()+1}/${kstNow.getDate()} ${h}:${min} 기준 (집계 중)`;
} else {
  const yesterday = new Date(kstNow);
  yesterday.setDate(yesterday.getDate() - 1);
  targetDate = yesterday.toISOString().slice(0, 10);
  const m = yesterday.getMonth() + 1;
  const d = yesterday.getDate();
  const dow = ['일','월','화','수','목','금','토'][yesterday.getDay()];
  label = `${m}/${d}(${dow}) 확정`;
}

const fromDate = targetDate + ' 00:00:00';
const toDate = targetDate + ' 23:59:59';
const st11Date = targetDate.replace(/-/g, '');

// 이번 달 누계용 (월 시작~전일)
const monthStart = targetDate.slice(0, 7) + '-01 00:00:00';

return [{ json: { chatId, mode, targetDate, fromDate, toDate, st11Date, monthStart, label } }];

// 네이버 커머스 API: require('crypto') HMAC + httpRequest로 토큰 발급
const crypto = require('crypto');
const clientId = $env.NAVER_COMMERCE_CLIENT_ID || '';
const clientSecret = $env.NAVER_COMMERCE_CLIENT_SECRET || '';

if (!clientId || !clientSecret) {
  return [{ json: { error: 'NAVER_COMMERCE 환경변수 미설정', accessToken: '' } }];
}

try {
  const timestamp = Date.now();
  const message = clientId + '_' + timestamp;
  const signature = crypto.createHmac('sha256', clientSecret).update(message).digest('base64');

  const tokenData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.commerce.naver.com/external/v1/oauth2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'client_id=' + encodeURIComponent(clientId) + '&timestamp=' + timestamp + '&client_secret_sign=' + encodeURIComponent(signature) + '&grant_type=client_credentials&type=SELF'
  });

  if (!tokenData.access_token) {
    return [{ json: { error: 'Token: ' + JSON.stringify(tokenData).slice(0, 200), accessToken: '' } }];
  }
  return [{ json: { accessToken: tokenData.access_token, error: '' } }];
} catch (e) {
  // 에러 응답 본문 추출
  const respBody = e.response && e.response.data ? JSON.stringify(e.response.data).slice(0, 200) : '';
  return [{ json: { error: 'Naver auth ' + e.message + (respBody ? ' | ' + respBody : ''), accessToken: '' } }];
}

// 네이버 주문 조회 (httpRequest 사용)
const token = $('네이버 인증').first().json.accessToken || '';
const dateInfo = $('날짜 계산').first().json;

if (!token) {
  return [{ json: { error: $('네이버 인증').first().json.error || 'No token', totalRevenue: 0, totalOrders: 0 } }];
}

try {
  const startTime = dateInfo.targetDate + 'T00:00:00.000+09:00';
  const endTime = dateInfo.targetDate + 'T23:59:59.999+09:00';

  let allOrders = [];
  let pageToken = '';
  let hasMore = true;

  while (hasMore) {
    const reqBody = { startTime, endTime, rangeType: 'PAYED', pageSize: 100 };
    if (pageToken) reqBody.pageToken = pageToken;

    const data = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.commerce.naver.com/external/v1/pay-order/seller/orders/search',
      headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
      body: reqBody
    });

    const contents = (data.data && data.data.contents) || data.contents || [];
    allOrders = allOrders.concat(contents);
    pageToken = (data.data && data.data.nextToken) || data.nextToken || '';
    hasMore = !!pageToken;
  }

  const CANCEL = ['CANCELED', 'RETURNED', 'EXCHANGED', 'CANCEL_REQUEST', 'RETURN_REQUEST'];
  let totalRevenue = 0, totalOrders = 0, cancelCount = 0;

  for (const o of allOrders) {
    const status = o.orderStatus || o.productOrderStatus || '';
    if (CANCEL.includes(status)) { cancelCount++; continue; }
    totalRevenue += parseInt(o.totalPaymentAmount || o.productOrderAmount || 0);
    totalOrders++;
  }

  return [{ json: { totalRevenue, totalOrders, cancelCount, rawCount: allOrders.length, error: '' } }];
} catch (e) {
  return [{ json: { error: 'Naver orders: ' + e.message, totalRevenue: 0, totalOrders: 0 } }];
}

// 11번가 주문 조회 (httpRequest + XML 간이 파싱)
const apiKey = $env.ST11_API_KEY || '';
const dateInfo = $('날짜 계산').first().json;

if (!apiKey) {
  return [{ json: { error: 'ST11_API_KEY 미설정', totalRevenue: 0, totalOrders: 0 } }];
}

try {
  const dateParam = dateInfo.st11Date;
  let allOrders = [];
  let page = 1;
  let hasMore = true;

  while (hasMore && page <= 20) {
    const xml = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.11st.co.kr/rest/ordservices/complete',
      qs: { dateType: 'ODD', startDate: dateParam, endDate: dateParam, pageNum: page, pageSize: 100 },
      headers: { 'openapikey': apiKey },
      returnFullResponse: false,
      encoding: 'utf-8'
    });

    const xmlStr = typeof xml === 'string' ? xml : JSON.stringify(xml);
    const orderMatches = xmlStr.match(/<order>[\s\S]*?<\/order>/g) || [];
    if (orderMatches.length === 0) { hasMore = false; break; }

    for (const chunk of orderMatches) {
      const g = (f) => { const m = chunk.match(new RegExp('<' + f + '>([^<]*)</' + f + '>')); return m ? m[1] : ''; };
      allOrders.push({ selPrc: parseInt(g('selPrc') || '0'), ordQty: parseInt(g('ordQty') || '1') });
    }

    page++;
    if (orderMatches.length < 100) hasMore = false;
  }

  let totalRevenue = 0, totalOrders = 0;
  for (const o of allOrders) { totalRevenue += o.selPrc * o.ordQty; totalOrders++; }

  return [{ json: { totalRevenue, totalOrders, rawCount: allOrders.length, error: '' } }];
} catch (e) {
  return [{ json: { error: '11st: ' + e.message, totalRevenue: 0, totalOrders: 0 } }];
}

// CRM 직접거래: NocoDB에서 최근 명세표 조회 후 날짜 필터
const dateInfo = $('날짜 계산').first().json;
const token = $env.NOCODB_TOKEN || '';

if (!token) {
  return [{ json: { list: [], error: 'NOCODB_TOKEN 미설정' } }];
}

try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pu0mwk97kac8a5p/ml81i9mcuw0pjzk',
    headers: { 'xc-token': token },
    qs: { sort: '-invoice_date', fields: 'Id,invoice_date,total_amount,payment_status', limit: 500 }
  });

  const allInvoices = data.list || [];
  const filtered = allInvoices.filter(inv => String(inv.invoice_date || '').startsWith(dateInfo.targetDate));

  return [{ json: { list: filtered, error: '' } }];
} catch (e) {
  return [{ json: { list: [], error: 'CRM: ' + e.message } }];
}

const dateInfo = $('날짜 계산').first().json;

// ── 1. 메이크샵 파싱 ──
let msRevenue = 0, msOrders = 0, msCancels = 0;
try {
  let orderResp = $('메이크샵 주문 조회').first().json;
  if (typeof orderResp.data === 'string') {
    try { orderResp = JSON.parse(orderResp.data); } catch(e) {}
  }
  if (typeof orderResp === 'string') {
    try { orderResp = JSON.parse(orderResp); } catch(e) { orderResp = {}; }
  }
  const rawList = Array.isArray(orderResp.list) ? orderResp.list : (orderResp.list ? Object.values(orderResp.list) : []);
  const CANCEL = ['60', '70', '80'];
  for (const entry of rawList) {
    const o = entry.order || entry;
    const status = String(o.order_status || o.ord_state || '');
    const amount = parseInt(o.pay_price || o.total_product_price || o.start_price || 0);
    if (CANCEL.includes(status)) { msCancels++; continue; }
    msRevenue += amount;
    msOrders++;
  }
} catch(e) {}

// ── 2. 네이버 ──
let nvRevenue = 0, nvOrders = 0, nvError = '';
try {
  const nv = $('네이버 주문 조회').first().json;
  nvRevenue = nv.totalRevenue || 0;
  nvOrders = nv.totalOrders || 0;
  nvError = nv.error || '';
} catch(e) { nvError = e.message; }

// ── 3. 11번가 ──
let stRevenue = 0, stOrders = 0, stError = '';
try {
  const st = $('11번가 주문 조회').first().json;
  stRevenue = st.totalRevenue || 0;
  stOrders = st.totalOrders || 0;
  stError = st.error || '';
} catch(e) { stError = e.message; }

// ── 4. CRM 직접거래 ──
let crmRevenue = 0, crmOrders = 0;
try {
  const crmResp = $('CRM 직접거래 조회').first().json;
  const invoices = crmResp.list || [];
  for (const inv of invoices) {
    if (inv.payment_status === 'cancelled') continue;
    crmRevenue += parseInt(inv.total_amount || 0);
    crmOrders++;
  }
} catch(e) {}

// ── 총계 ──
const totalRevenue = msRevenue + nvRevenue + stRevenue + crmRevenue;
const totalOrders = msOrders + nvOrders + stOrders + crmOrders;
const fmt = (n) => n.toLocaleString('ko-KR');
const pct = (n) => totalRevenue > 0 ? Math.round(n / totalRevenue * 100) : 0;

// ── 리포트 생성 ──
let msg = '<b>[전일 매출] ' + dateInfo.label + '</b>\n';
msg += '━━━━━━━━━━━━━━━━━━━\n';
msg += '\uD83D\uDCB0 총 매출: <b>' + fmt(totalRevenue) + '원</b> (' + totalOrders + '건)\n\n';
msg += '채널별:\n';
msg += '\uD83C\uDFEA 메이크샵  ' + fmt(msRevenue) + '원 (' + msOrders + '건) ' + pct(msRevenue) + '%';
if (msCancels > 0) msg += ' | 취소 ' + msCancels + '건';
msg += '\n';

if (nvError) {
  msg += '\uD83D\uDFE2 네이버     (API 오류)\n';
} else {
  msg += '\uD83D\uDFE2 네이버     ' + fmt(nvRevenue) + '원 (' + nvOrders + '건) ' + pct(nvRevenue) + '%\n';
}

if (stError) {
  msg += '\uD83D\uDD34 11번가     (API 오류)\n';
} else {
  msg += '\uD83D\uDD34 11번가     ' + fmt(stRevenue) + '원 (' + stOrders + '건) ' + pct(stRevenue) + '%\n';
}

msg += '\uD83D\uDCDE 직접거래  ' + fmt(crmRevenue) + '원 (' + crmOrders + '건) ' + pct(crmRevenue) + '%\n';
msg += '\u2B1C 쿠팡       (미연동)\n';

// 에러 요약
const errors = [];
if (nvError) errors.push('네이버: ' + nvError.slice(0, 50));
if (stError) errors.push('11번가: ' + stError.slice(0, 50));
if (errors.length > 0) {
  msg += '\n\u26A0\uFE0F API 오류:\n' + errors.map(e => '  · ' + e).join('\n') + '\n';
}

if (totalOrders === 0) {
  msg = '<b>[전일 매출] ' + dateInfo.label + '</b>\n━━━━━━━━━━━━━━━━━━━\n주문이 없습니다.';
  if (errors.length > 0) msg += '\n\n\u26A0\uFE0F API 오류 (데이터 불완전):\n' + errors.map(e => '  · ' + e).join('\n');
}

return [{ json: {
  message: msg,
  chatId: dateInfo.chatId,
  reportDate: dateInfo.targetDate,
  makeshop: { revenue: msRevenue, orders: msOrders, cancels: msCancels },
  naver: { revenue: nvRevenue, orders: nvOrders, error: nvError },
  st11: { revenue: stRevenue, orders: stOrders, error: stError },
  crm: { revenue: crmRevenue, orders: crmOrders },
  total: { revenue: totalRevenue, orders: totalOrders },
  sheetsRow: (function() {
    const p = dateInfo.targetDate.split('-').map(Number);
    const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
    const jan1 = new Date(Date.UTC(2026, 0, 1));
    return Math.round((target - jan1) / 86400000) + 2;
  })()
} }];
